pub fn object_acronym(code: u16) -> Option<&'static str> {
    OBJECT_CLASSES.iter().find(|(c, _)| *c == code).map(|(_, a)| *a)
}

pub fn attribute_acronym(code: u16) -> Option<&'static str> {
    ATTRIBUTES.iter().find(|(c, _)| *c == code).map(|(_, a)| *a)
}

